void closeOk()
{
    if(!ETGCanadaParameters::find().EnableExcludeCustomizations)
    {
        ProdJournalBOM              prodJournalBOM, prodJournalBOMPost, prodJournalBOMloc;
        ProdParmReportFinished      prodParmReportFinished, prodParmReportFinishedloc, prodParmReportFinishedFormula;
        ProdJournalTable            prodJournalTable, prodJournalTableRAF;
        ParmId                      parmId;
        Qty                         consump, rafQty;
        Dialogbutton                db;
        boolean                     packingFind;
        InventItemGroupItem         inventItemGroupItem;
        ProdJournalProd             prodJournalProd;

        consump = 0; rafQty = 0;
        FormRun         formRun = this;
        prodParmReportFinishedloc = formrun.dataSource(formDataSourceStr(ProdParmReportFinished,ProdParmReportFinished)).cursor();

        select * from prodParmReportFinishedFormula
             where prodParmReportFinishedFormula.ParmId == prodParmReportFinishedloc.ParmId
                && prodParmReportFinishedFormula.PmfProductType == PmfProductType::Formula;
        if (!prodParmReportFinishedFormula.QtyGood || prodParmReportFinishedFormula.QtyGood <= 0)
        {
            throw Error('Formula should not be empty or Negative');
        }


        parmId = prodMultiReportFinished.ParmId();

        select sum(QtyGood) from  prodParmReportFinished group by prodParmReportFinished.ParmId
            where prodParmReportFinished.ParmId == parmId;

        while select * from prodJournalTable
            where prodJournalTable.ProdId == prodParmReportFinishedloc.ProdId
                && prodJournalTable.JournalType == ProdJournalType::Picklist
        {

            if (!packingFind)
            {
                while select * from prodJournalBOMloc
                where prodJournalBOMloc.ProdId == prodJournalTable.ProdId
                join inventItemGroupItem
                    where  inventItemGroupItem.ItemId == prodJournalBOMloc.ItemId
                    && inventItemGroupItem.ItemGroupId == "PK"
                {
                    packingFind = true;
                }

                if (!packingFind)
                {
                    if (!prodJournalBOMloc)
                    {
                        //checkFailed(strFmt("Packing material not posted for this order"));
                        db = box::yesNo("Packing material not posted for this order, Would you like to proceed?", dialogButton::Yes, "YesNo Box Example");
                        if(db == Dialogbutton::No)
                        {
                            throw error(strFmt('Packing material not posted for this order'));;
                        }

                    }
                }
                else
                {
                    if (prodJournalTable.Posted == NoYes::No)
                    {
                        db = box::yesNo("Packing material not posted for this order, Would you like to proceed?", dialogButton::Yes, "YesNo Box Example");
                        if(db == Dialogbutton::No)
                        {
                            throw error(strFmt('Packing material not posted for this order'));;
                        }
                    }
                }
            }

            select sum(BOMConsump) from prodJournalBOM group by prodJournalBOM.JournalId
                    where prodJournalBOM.JournalId == prodJournalTable.JournalId
                join inventItemGroupItem
                    where  inventItemGroupItem.ItemId == prodJournalBOM.ItemId
                    && (inventItemGroupItem.ItemGroupId == "RM" || inventItemGroupItem.ItemGroupId == "SFG");

            consump += prodJournalBOM.BOMConsump;
        }

        while select * from prodJournalTableRAF
            where prodJournalTableRAF.ProdId == prodParmReportFinishedloc.ProdId
            && prodJournalTableRAF.JournalType == ProdJournalType::ReportFinished
        {

            select sum(QtyGood) from prodJournalProd group by prodJournalProd.JournalId
                    where prodJournalProd.JournalId == prodJournalTableRAF.JournalId;

            rafQty += prodJournalProd.QtyGood;
        }


        if (consump < rafQty + prodParmReportFinished.QtyGood)
        {
            throw error(strFmt('Input-Out quantities are not Matching'));
        }

        if(prodParmReportFinished.QtyGood > consump)
        {

            throw error(strFmt('Input-Out quantities are not Matching'));

        }
        else
        {
            if(prodParmReportFinished.QtyGood < consump)

            {
                //checkFailed(strFmt('Input-Out quantities are not Matching'));
                db = box::yesNo("Input-Out quantities are not Matching, Would you like to proceed?", dialogButton::Yes, "YesNo Box Example");
                if(db == Dialogbutton::No)
                {
                    throw error(strFmt('Input-Out quantities are not Matching'));;
                }
            }
        }


        // date validation
        prodJournalBOMloc.clear();
        prodParmReportFinishedFormula.clear();

        while select TransDate from prodParmReportFinishedFormula
        where prodParmReportFinishedFormula.ProdId == prodParmReportFinishedloc.ProdId
            && prodParmReportFinishedFormula.ParmId == prodParmReportFinishedloc.ParmId
        {
            while select TransDate from prodJournalBOMloc where prodJournalBOMloc.ProdId == prodParmReportFinishedloc.ProdId
            {
                if (prodJournalBOMloc.TransDate > prodParmReportFinishedFormula.TransDate)
                {
                    throw error ('RAF Date should be greater than picking list posted date');
                }
            }
        }
    }





    next closeOk();
}

/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormDataFieldEventHandler(formDataFieldStr(ProdParmReportFinished, InventDim, inventBatchId), FormDataFieldEventType::Modified)]
public static void inventBatchId_OnModified(FormDataObject sender, FormDataFieldEventArgs e)
{
    if(!ETGCanadaParameters::find().EnableExcludeCustomizations)
    {
        ProdParmReportFinished     prodParmReportFinished,prodParmReportFinishedLoc;
        InventDim                 inventDim,inventDimLoc, inventdimupd;
        FormRun         formrun = sender.datasource().formRun();
        FormDataSource  ProdParmReportFinished_ds = formrun.dataSource(formDataSourceStr(ProdParmReportFinished, ProdParmReportFinished));
        FormDataSource  inventdim_ds = formrun.dataSource(formDataSourceStr(ProdParmReportFinished, InventDim));

        inventDimLoc = inventdim_ds.cursor();
        prodParmReportFinished = ProdParmReportFinished_ds.cursor();

        while select forupdate  prodParmReportFinishedLoc
        where prodParmReportFinishedLoc.ParmId == prodParmReportFinished.ParmId
            && prodParmReportFinishedLoc.ProdId == prodParmReportFinished.ProdId
        {
            ttsbegin;
            select forupdate inventDim where inventDim.inventDimId == prodParmReportFinishedLoc.InventDimId;

            inventDim.inventBatchId = inventDimLoc.inventBatchId;
            inventdimupd = InventDim::findOrCreate(inventDim);
            prodParmReportFinishedLoc.InventDimId = inventdimupd.inventDimId;
            prodParmReportFinishedLoc.ETGBatchCreationDate = today();
            prodParmReportFinishedLoc.doUpdate();
            ttscommit;
        }

        prodParmReportFinished_ds.reread();
        prodParmReportFinished_ds.executeQuery();
    }
}

