    {
        ProdParmReportFinished     prodParmReportFinished,prodParmReportFinishedLoc;
        InventDim                 inventDim,inventDimLoc, inventdimupd;
        FormRun         formrun = sender.datasource().formRun();
        FormDataSource  ProdParmReportFinished_ds = formrun.dataSource(formDataSourceStr(ProdParmReportFinished, ProdParmReportFinished));
        FormDataSource  inventdim_ds = formrun.dataSource(formDataSourceStr(ProdParmReportFinished, InventDim));

        inventDimLoc = inventdim_ds.cursor();
        prodParmReportFinished = ProdParmReportFinished_ds.cursor();

        while select forupdate  prodParmReportFinishedLoc
        where prodParmReportFinishedLoc.ParmId == prodParmReportFinished.ParmId
            && prodParmReportFinishedLoc.ProdId == prodParmReportFinished.ProdId
