    // FormDataSource  inventdim_ds = formrun.dataSource(formDataSourceStr(ProdParmReportFinished, Pool));

    //inventDimLoc = inventdim_ds.cursor();
    prodParmReportFinished = ProdParmReportFinished_ds.cursor();

    while select forupdate  prodParmReportFinishedLoc
        where prodParmReportFinishedLoc.ParmId == prodParmReportFinished.ParmId
            && prodParmReportFinishedLoc.ProdId == prodParmReportFinished.ProdId
    {
        ttsbegin;
        //select forupdate prodParmReportFinished where prodParmReportFinished.ETGProductionShift == prodParmReportFinishedLoc.ETGProductionShift;


        prodParmReportFinishedLoc.ETGProductionShift = prodParmReportFinished.ETGProductionShift;
        prodParmReportFinishedLoc.doUpdate();
        ttscommit;
    }

    prodParmReportFinished_ds.reread();
