public int active()
{
    int ret;
    FormDatasource     InventDim_Ds;

    InventDim_Ds.object(fieldNum(InventDim,InventBatchId)).mandatory(true);

    return ret;
}

/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(ProdParmReportFinished, Ok), FormControlEventType::Clicked)]
public static void Ok_OnClicked(FormControl sender, FormControlEventArgs e)
{

    ProdParmReportFinished  prodParmReportFinished, prodParmReportFinishedloc;
    InventSum       inventsum, inventsumloc;
    InventDim  inventdim;

    prodParmReportFinished = sender.formRun().dataSource(formDataSourceStr(ProdParmReportFinished,ProdParmReportFinished)).cursor();

    while select forupdate  prodParmReportFinishedLoc
        where prodParmReportFinishedLoc.ParmId == prodParmReportFinished.ParmId
            && prodParmReportFinishedLoc.ProdId == prodParmReportFinished.ProdId
    {
        inventsum.clear();
        inventDim.clear();
        inventsumloc.clear();
        ttsbegin;

        select forupdate inventsum where inventsum.ItemId == prodParmReportFinishedLoc.ItemId && inventsum.InventDimId == prodParmReportFinishedLoc.InventDimId;
        if (inventsum.RecId)
        {
            inventsum.AvailOrdered      += 0;//prodParmReportFinishedLoc.QtyGood;
            inventsum.PhysicalInvent    += 0;//prodParmReportFinishedLoc.QtyGood;
            inventsum.Registered        += 0;//prodParmReportFinishedLoc.QtyGood;
            inventsum.AvailPhysical     += 0;//prodParmReportFinishedLoc.QtyGood;
            inventsum.doUpdate();
        }
        else
        {
            inventsumloc.ItemId            = prodParmReportFinishedLoc.ItemId;
            inventsumloc.AvailOrdered      = 0;//prodParmReportFinishedLoc.QtyGood;
            inventsumloc.PhysicalInvent    = 0;//prodParmReportFinishedLoc.QtyGood;
            inventsumloc.Registered        = 0;//prodParmReportFinishedLoc.QtyGood;
            inventsumloc.AvailPhysical     = 0;//prodParmReportFinishedLoc.QtyGood;
            inventsumloc.InventDimId       = prodParmReportFinishedLoc.inventDimId;
            inventsumloc.insert();
        }

        ttscommit;
    }

}
